var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"이런 좁은 장소에서… 훈련된 전투부대와 호각으로 싸운다고?","JPN":"こんな限られたスペースしかない場所で……熟練の戦闘部隊と互角で戦うだと？","ENG":"How is she able to fight on par with a professionally trained combat unit in such a narrow place...?","TWN":"在這麼狹窄的空間…竟然可以和訓練有素的戰鬥部隊抗衡？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"더 이상의 살생과 저항은 무의미하다고 판단되오.","JPN":"これ以上の犠牲と、抵抗は無駄だと思われます。","ENG":"Further killing and resistance is futile.","TWN":"不要再繼續無謂的殺生和抵抗。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이제 그만 포기하는 걸 권하리다.","JPN":"もう諦めてはどうでしょう。","ENG":"I suggest you surrender.","TWN":"勸你們棄械投降。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"흥, 협상을 원한다는 건 결국 네놈도 지쳐간다는 뜻이지.","JPN":"ふん、そうやって歩み寄ってきたということは、どうせ貴様だって体力が尽きてきているんだろう。","ENG":"Hmph. Negotiation only means that you are getting tired.","TWN":"哼，想要休兵就表示你不行了吧？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"하지만 이쪽은 아직 한참 남았다.","JPN":"だが、こっちにはまだまだ余力がある。","ENG":"Unfortunately for you, we still have more men to count.","TWN":"但我們還有餘力呢。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"그만 두시죠, 지휘관님.","JPN":"そのくらいにしましょう、指揮官。","ENG":"Commander, I think it's time you stopped.","TWN":"指揮官，住手。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"…뭐냐? 비전투인원은 밖에서 기다리라고 했을 텐데.","JPN":"……何だ？　非戦闘員は外で待機するよう、命令したはずだが。","ENG":"...What? I thought I told all non-combatants to wait outside.","TWN":"…搞什麼？我不是說非作戰人員一律在外等候嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"상관의 명령이 말 같지 않나? 부사관?","JPN":"上官の命令に逆らっていいとでも？　下士官？","ENG":"You dare defy my orders, Sergeant?","TWN":"你把長官的話當耳邊風嗎，副官？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"저 여자 말이 맞습니다. 요령도 없이 머릿수로 밀어붙이는 짓은 그만두자고요.","JPN":"あの女の言うとおりです。人員数にかまけて無駄に攻め続けるのはやめましょう。","ENG":"The girl is right. We should stop these mindless attacks based on numbers.","TWN":"她說的沒錯，沒本事只能靠人數優勢，這樣吃相太難看。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"병사들이 아깝잖아요? 아무리 파리 같은 목숨이라도.","JPN":"いくら虫同然の価値しかないとはいえ、兵士の命がもったいなくはありませんか？","ENG":"It is a waste of manpower, don't you think? Even if their lives are worthless.","TWN":"士兵只是無謂地犧牲不是嗎？雖然他們死不足惜。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"입단한 지 얼마 되지도 않은 풋내기가 부사령관님께서 좀 예뻐해 주셨다고 건방을 떠는군.","JPN":"入団して間もない貴様が、副司令官に少し気に入られたからと調子に乗りやがって。","ENG":"Getting cocky that you're on the deputy commander's good side, eh?","TWN":"你一個才剛加入沒多久的新人，因為副司令官喜歡你，就這麼目中無人嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"애초에 네 역할은 엘릭서를 만들고 파는 것뿐이다.","JPN":"そもそも貴様の役割はエリクサーを作り、売ることだろう。","ENG":"Your role in all of this is to only make and sell the Elixir, boy.","TWN":"你的功能就只是製作販賣聖水而已。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"내가 주관하는 작전에 주제넘게 참견 말도록.","JPN":"私が指揮を執る作戦に、口を出すのはやめろ。","ENG":"Stop interfering with my operation. I'm the one in charge here.","TWN":"這場作戰是由我來主導，沒有你插嘴的餘地。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"애초에 제 계획이 아니었으면 저 여자를 여기까지 끌어들이지도 못했을 텐데요.","JPN":"私の計画がなかったら、そもそもあの女をここに連れてくることはできなかったと思いますが。","ENG":"If it weren't for my plans, you wouldn't have been able to lure her here.","TWN":"要不是我想到這個辦法，能把那女的引到這裡來嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"흥…","JPN":"ほう……？","ENG":"Hmph...","TWN":"哼…"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_MO","text":{"KOREA":"그렇게 말하는 네놈은 저 괴물을 제압할 다른 좋은 수라도 있나?","JPN":"ならば聞こう。貴様にはあの化け物を制圧する妙策でもあるのか？","ENG":"Then, pray tell, what is your brilliant plan for subduing that monster?","TWN":"你這麼有辦法，那你倒是說說看要怎麼制伏那個怪物？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"COMMANDER_REPLACER_NULL_MO","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"물론이죠.","JPN":"もちろんです。","ENG":"Just a moment.","TWN":"沒問題。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"시간을 조금만 주시면, 제가 잘 설득해보겠습니다.","JPN":"少し時間をいただければ、私から説得してみます。","ENG":"If you give me some time, I'll try to persuade her.","TWN":"給我點時間，我會說服她。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};